namespace sv_f051c7add9024b30aa4b454b55e26b9e.Services;

/// <summary>
/// Scoped service (one per SignalR circuit) that holds the currently selected
/// warehouse and notifies all subscribed components when the selection changes.
/// </summary>
public sealed class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    /// <summary>
    /// Raised on the caller's thread whenever the warehouse changes.
    /// Subscribers must marshal to their own sync context if needed.
    /// </summary>
    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (warehouseId == _currentWarehouseId)
            return;

        if (AvailableWarehouses.All(w => w.Id != warehouseId))
            throw new ArgumentException($"Unknown warehouse: {warehouseId}");

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_f051c7add9024b30aa4b454b55e26b9e.Services;

/// <summary>
/// Scoped service (one per circuit) that provides low-stock alert counts
/// and broadcasts notifications so every subscribed component updates together.
/// </summary>
public sealed class InventoryAlertService
{
    private int _latestCount;

    public int LatestCount => _latestCount;

    /// <summary>Raised after new alert data is fetched. All subscribers update together.</summary>
    public event Action? OnAlertDataChanged;

    /// <summary>Simulates a database query – returns a random count between 0 and 15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = Random.Shared.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches a new count for the given warehouse, caches it, and notifies all subscribers.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        _latestCount = await GetLowStockCountAsync(warehouseId);
        OnAlertDataChanged?.Invoke();
    }
}

