@page "/dashboard"
@rendermode InteractiveServer
@implements IDisposable
@inject Services.WarehouseStateService WarehouseState
@inject Services.InventoryAlertService AlertService

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<p class="lead">
    Viewing: <strong>@WarehouseState.CurrentWarehouseName</strong>
    <span class="text-muted">(@WarehouseState.CurrentWarehouseId)</span>
</p>

<div class="card" style="max-width: 26rem;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        @if (_loading)
        {
            <p class="text-muted">Checking inventory…</p>
        }
        else
        {
            <p class="display-6">
                @AlertService.LatestCount
                <span class="fs-6 text-muted">item(s) below minimum</span>
            </p>
        }
        <p class="text-muted small mb-0">Auto-refreshes every 10 seconds while this page is open.</p>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.OnAlertDataChanged += HandleAlertDataChanged;

        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _loading = false;

        _cts = new CancellationTokenSource();
        _ = PollAsync(_cts.Token);
    }

    private async Task PollAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException) { }
    }

    private async void HandleWarehouseChanged()
    {
        _loading = true;
        await InvokeAsync(StateHasChanged);

        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _loading = false;
        await InvokeAsync(StateHasChanged);
    }

    private void HandleAlertDataChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertService.OnAlertDataChanged -= HandleAlertDataChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

